	 ('Técnico de Enfermagem','Técnico-Clínico','5dbcddb7-6b25-438a-bb54-7313b3dcd171','Identifica e comunica sinais de gravidade imediata ao Enfermeiro/médico com precisão e agilidade',1,'Triagem e comunicação',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Técnico de Enfermagem','EIXO TÉCNICO','','Executa corretamente compressões torácicas, ventilação (bolsa-valva-máscara) e desfibrilação com DEA conforme protocolo RCP e DEA?',1,'O protocolo de Suporte Básico de Vida (SBV) para PCR baseia-se na sequência C-A-B-D.',true,'2026-06-30 13:18:28.638346','autoavaliacao'),
	 ('Técnico de Enfermagem','Metas e desenvolvimento - Transversais','','Busco ativamente meu desenvolvimento profissional por meio de capacitações, leituras, treinamentos inlocco, e trocas com equipe?',1,'Essa postura de aprendizagem contínua - chamada de Lifelong Learning - é essencial para manter a empregabilidade, desenvolver novas competências e destacar-se no mercado atual',true,'2026-06-30 13:24:24.86345','autoavaliacao'),
	 ('Condutor','Gestão de Qualidade','db166c86-7fa9-4bcf-8051-8d3093b489ee','Garante que todos os membros conheçam e sigam os protocolos clínicos e operacionais do SAMU-192/CRUR-BF.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Condutor','Gestão de Qualidade','7c498c53-16d9-45ba-9e3a-b811de1b2c4b','Lidera iniciativas de segurança do paciente e promove o uso rigoroso dos EPIs.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Condutor','Suporte e desenvolvimento','','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI)?',2,'Garantir feedback mensal para 100% da equipe operacional. Identificar lacunas de competência no atendimento de urgência. ',true,'2026-06-30 16:29:11.896276','Liderado > Lider'),
	 ('Enfermeiro','Suporte e desenvolvimento','','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',true,'2026-06-30 16:30:14.65642','Liderado > Lider'),
	 ('Enfermeiro','Liderança gestão','','As decisões do líder são tomadas com transparência critérios técnicos e considerando o impacto na equipe?',2,'No contexto do SAMU, tomar decisões técnicas (como seguir à risca os protocolos de triagem ou priorização de viaturas) e explicar os motivos de forma transparente para a equipe evita boatos na base e fortalece a confiança no comando.',true,'2026-06-30 13:32:48.121518','Liderado > Lider'),
	 ('Técnico de Enfermagem','EIXO TÉCNICO ','','Manuseia corretamente: oxímetro, monitor cardíaco, respirador, glicosímetro e demais equipamentos da USB/USA Manuseio de equipamentos?',1,'O manuseio adequado foca na segurança do paciente, estabilização dos sinais vitais e transporte seguro',true,'2026-06-30 13:19:15.285353','autoavaliacao');
INSERT INTO public.criterios_avaliacao (tipo,categoria,codigo,criterio,peso,indicador,ativo,created_at,avaliacao) VALUES
	 ('Condutor','Suporte e desenvolvimento','','O líder incentiva a desenvolvimento profissional da equipe, apoiando capacitações e o crescimento na carreira?',2,'Incentiva a equipe a fazer cursos de especialização (como suporte avançado de vida) e progredir na carreira de urgência e emergência.',true,'2026-06-30 16:29:41.288345','Liderado > Lider'),
	 ('Enfermeiro','Comportamental','ae53903f-c7ff-4df7-8445-9ac4bf70af20','Mantém foco e equilíbrio emocional em situações de alta pressão (PCR, múltiplas vítimas, violência)',1,'Controle emocional',true,'2026-06-11 15:06:08.472675','autoavaliacao'),
	 ('Condutor','Comportamental','05c29064-8c19-44cd-8749-66ce88f2a10f','Mantém controle emocional em cenários de alta tensão, múltiplas vítimas, violência ou óbito',1,'Controle emocional',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Condutor','Técnico-Operacional','7b6b8a10-02af-49a6-8178-cc00c3dc260e','Manuseia corretamente a maca, cadeira de rodas, prancha longa e colar cervical',1,'Manuseio de equipamentos',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Condutor','Eixo SOFT SKILLS','d8dbf442-1ccc-4a53-b6bd-9294630c2a2e','Mantém controle emocional em cenários de alta tensão, múltiplas vítimas, violência ou óbito Controle emocional.',1,'Manter o controle emocional é vital para a segurança e a eficácia da equipe. Gerencie o estresse focando no momento presente, adotando técnicas de respiração e separando a empatia do sofrimento.',true,'2026-06-30 11:03:42.352605','autoavaliacao'),
	 ('Técnico de Enfermagem','Gestão e Liderança','034ee1a4-1ab2-4465-8edf-593ed01de36e','Medeia conflitos interpessoais de forma profissional, imparcial e orientada para a solução.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Médico','Liderança','7dfbadb3-0cae-4c7e-a161-5a80c80d98b0','Mantém consciência situacional ampla (cena, paciente, equipe, recursos, tempo) e adapta o plano de cuidado',1,'Consciência situacional NTS',true,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Enfermeiro','Gestão de Qualidade','5c4b0620-4366-4118-8bc0-7bbf77daa2e9','Monitora e divulga os indicadores de desempenho para a equipe, com análise e plano de ação.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Enfermeiro','Liderança gestão','','O líder demonstra domínio técnico e conhecimento das rotinas suficientes para orientar a equipe com segurança?',2,'o líder precisa dominar as rotinas operacionais (fluxos de regulação, protocolos contratuais) e os protocolos assistenciais de ponta (como o PHTLS, ACLS e diretrizes de trauma/cardio) para que a equipe sinta total segurança ao seguir suas ordens em situações críticas.',true,'2026-06-30 13:33:32.9942','Liderado > Lider'),
	 ('Técnico de Enfermagem','Metas e desenvolvimento - Transversais','','Tenho clareza sobre minhas motivações profissionais que nos mantém engajado no trabalho no SAMU 192',1,'As motivações para atuar no SAMU 192 geralmente giram em torno do propósito de salvar vidas, da adrenalina e dinamismo do Atendimento Pré-Hospitalar (APH) e do compromisso em fortalecer a saúde pública',true,'2026-06-30 13:25:18.41566','autoavaliacao');
INSERT INTO public.criterios_avaliacao (tipo,categoria,codigo,criterio,peso,indicador,ativo,created_at,avaliacao) VALUES
	 ('Enfermeiro','Comunicação e disponibilidade','','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos?',2,'A líder monitora ativamente os atendimentos diários para garantir a qualidade assistencial. Realiza o planejamento e ajuste da tripulação (escala) de forma justa e eficiente. Executa o processo de acolhimento e treinamento prático de novos colaboradores (onboarding).',true,'2026-06-30 13:34:48.761055','Liderado > Lider'),
	 ('Condutor','Desenvolvimento da Equipe','8f3d495a-375a-4ab9-b349-c900593c1883','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI).',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('BP-TEAM','Liderança','5388527d-20ac-4bab-a95a-bc31cf4ffe2d','O líder adapta o plano de cuidado conforme evolução clínica do paciente e novos achados da cena',1,'',true,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('BP-TEAM','Liderança','9f61c333-614b-425f-8b16-36863f69e76d','O líder dirige a equipe com clareza, define papéis e responsabilidades desde o início do atendimento',1,'',true,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Médico','Gestão de Qualidade','5ba8abb2-0819-492f-b4fb-0d99901e4bc8','Monitora e divulga os indicadores de desempenho para a equipe, com análise e plano de ação.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Condutor','Técnico Operacional','c6bf0ae0-45d1-492f-bf57-b1b76166ee2e','Manuseia corretamente a maca, cadeira de rodas, prancha longa e colar cervical.',2,NULL,true,'2026-06-16 13:01:16.376169','Lider > Liderado'),
	 ('Condutor','Eixo técnico','e144214d-77a0-4499-9b96-a7c5f67d70e8','Manuseia corretamente a maca, cadeira de rodas, prancha longa e colar cervical (Manuseio de equipamentos)',1,'Manuseio correto de equipamentos de imobilização e transporte exige treinamento, comunicação constante e movimentação em bloco.',true,'2026-06-30 11:16:11.659225','autoavaliacao'),
	 ('Técnico de Enfermagem','Comportamental','303490e6-6d79-40ea-b643-f31e55ee26a7','Mantém foco e equilíbrio emocional em situações de alta pressão (PCR, múltiplas vítimas, violência)',1,'Controle emocional',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Técnico de Enfermagem','Comportamental','33629e16-1f1b-4400-9867-e4795e3dae90','Mantém consciência situacional: monitora o estado do paciente, equipamentos e ambiente simultaneamente',1,'Consciência situacional NTS',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Técnico de Enfermagem','Técnico-Clínico','e8f752f9-706d-4757-8bb5-a9a28188eef3','Manuseia corretamente: oxímetro, monitor cardíaco, respirador, glicosímetro e demais equipamentos da USB/USA',1,'Manuseio de equipamentos',false,'2026-06-10 10:02:38.389329','autoavaliacao');
