INSERT INTO public.criterios_avaliacao (tipo,categoria,codigo,criterio,peso,indicador,ativo,created_at,avaliacao) VALUES
	 ('Técnico de Enfermagem','Desenvolvimento da Equipe','1c804f87-39a1-40d6-af09-d7fdb45f4cc0','Promove e facilita atividades de educação permanente, simulações e capacitações na base do SAMU.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Condutor','Liderança gestão','','O(s) líder coordena a equipe de forma organizada, distribuindo tarefas com clarezas e justiça?',2,'isso é fundamental para garantir que as escalas de plantão, a divisão de responsabilidades pela checagem das viaturas (insumos/medicamentos) e a limpeza da base sejam feitas de forma equilibrada, sem sobrecarregar nenhum profissional.',true,'2026-06-30 13:32:04.689644','Liderado > Lider'),
	 ('Condutor','Suporte e desenvolvimento','','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',true,'2026-06-30 16:30:14.65642','Liderado > Lider'),
	 ('Enfermeiro','Comunicação e disponibilidade','','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'1.	No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',true,'2026-06-30 13:36:05.370723','Liderado > Lider'),
	 ('BP-TEAM','Gerenciamento de Tarefas','a2dd63a3-2325-414c-9616-120264c13e51','Os procedimentos são executados com técnica correta, sem erros ou omissões significativas',1,'',true,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Enfermeiro','Desenvolvimento da Equipe','a8748a99-e53a-4d41-b6f9-304e17c07849','Promove e facilita atividades de educação permanente, simulações e capacitações na base do SAMU.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Enfermeiro','Processo e Qualidade','0471eaf8-565e-49b2-a11e-bc6f028d796f','Preenche corretamente a ficha de atendimento pré-hospitalar com completude, clareza e fidelidade aos achados',1,'Qualidade do prontuário',true,'2026-06-11 15:06:08.472675','autoavaliacao'),
	 ('Médico','Desenvolvimento da Equipe','b0fc6761-2ed9-4396-af14-8f3cde7aee5b','Promove e facilita atividades de educação permanente, simulações e capacitações na base do SAMU.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Médico','Técnico-Clínico','ceb9dd23-617c-4593-96a5-f24998aa24c5','Realiza avaliação clínica completa e rápida, formulando diagnóstico sindromático correto no pré-hospitalar',1,'Diagnóstico pré-hospitalar',true,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Técnico de Enfermagem','Comunicação e disponibilidade','','O líder está disponível e acessível quando a equipe precisa de suporte, orientação ou decisão rápida?',2,'1.	onde os segundos salvam vidas e as crises operacionais acontecem a qualquer hora do dia ou da noite, ter um líder acessível para resolver impasses de frota, problemas na regulação ou conflitos na base é fundamental.',true,'2026-06-30 16:27:54.328435','Liderado > Lider');
