	 ('Técnico de Enfermagem','Trabalho em Equipe','bdc00349-90bc-4ed4-bef6-c99349bdbc3d','Sou receptivo(a) a feedbacks construtivos da equipe após uma ocorrência.',1,'',false,'2026-06-11 17:58:51.235499','autoavaliacao'),
	 ('Técnico de Enfermagem','Técnico-Clínico','1446a5a5-e763-4305-b2af-187d1ae16a72','Realiza punção venosa periférica, coleta e administra medicamentos conforme prescrição do Enfermeiro/médico',1,'Punção venosa / medicação',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Técnico de Enfermagem','Técnico-Clínico','b2863d5a-9137-4f00-bb36-74242016474d','Toma decisões clínicas rápidas e assertivas em cenários de IAM, AVC, trauma grave, sepse e PCR',1,'Decisão clínica em urgências',false,'2026-06-10 10:02:38.389329','autoavaliacao');
INSERT INTO public.criterios_avaliacao (tipo,categoria,codigo,criterio,peso,indicador,ativo,created_at,avaliacao) VALUES
	 ('Técnico de Enfermagem','EIXO TÉCNICO ','','Realiza punção venosa periférica, coleta e administra medicamentos conforme prescrição do Enfermeiro/médico Punção venosa / medicação?',1,'A punção venosa periférica e a administração de medicamentos são procedimentos regulamentados que exigem capacitação técnica e obediência estrita às prescrições do enfermeiro ou médico.',true,'2026-06-30 13:20:21.110296','autoavaliacao'),
	 ('Condutor','Gestão e Liderança','723cc997-ed62-47ae-9bdd-0d6d0f3c72d8','Toma decisões operacionais de forma ágil e embasada, consultando a equipe quando necessário.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Condutor','Relacionamento','9497b4e0-ada9-441c-b1af-cd91aa98e224','Reconhece publicamente os bons resultados e esforços individuais e coletivos da equipe.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Condutor','Liderança gestão','','As decisões do líder são tomadas com transparência critérios técnicos e considerando o impacto na equipe?',2,'No contexto do SAMU, tomar decisões técnicas (como seguir à risca os protocolos de triagem ou priorização de viaturas) e explicar os motivos de forma transparente para a equipe evita boatos na base e fortalece a confiança no comando.',true,'2026-06-30 13:32:48.121518','Liderado > Lider'),
	 ('Condutor','Técnico-Operacional','0a4e296f-d7c8-41e3-b6f4-e3e4f8b0b52a','Mantém a ambulância limpa, organizada e em condições sanitárias adequadas após cada atendimento',1,'Higienização ambulância',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Médico','Suporte e desenvolvimento','','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI)?',2,'Garantir feedback mensal para 100% da equipe operacional. Identificar lacunas de competência no atendimento de urgência. ',true,'2026-06-30 16:29:11.896276','Liderado > Lider'),
	 ('Condutor','Técnico-Operacional','fc3a64a7-f163-4308-aee7-b42349a5d49f','Auxilia a equipe nos procedimentos de Suporte Básico de Vida (SBV): RCP, imobilização, oxigenoterapia básica',1,'Competência SBV',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Enfermeiro','Gestão e Liderança','2df2e509-b3ec-498e-9339-1b672e1d941d','Medeia conflitos interpessoais de forma profissional, imparcial e orientada para a solução.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Enfermeiro','Liderança','8ae94c05-5cb8-4771-99f9-d75f4a3751f9','Usa comunicação em loop fechado (call-out, check-back) para garantir compreensão das ordens na cena',1,'Comunicação em loop (NTS)',true,'2026-06-11 15:06:08.472675','autoavaliacao'),
	 ('Enfermeiro','Comportamental','578d88f9-7951-48c1-b0fe-f185f6b37e76','Usa corretamente todos os EPIs e adota medidas de segurança para si, paciente e equipe em toda cena',1,'Segurança / EPIs',true,'2026-06-11 15:06:08.472675','autoavaliacao');
INSERT INTO public.criterios_avaliacao (tipo,categoria,codigo,criterio,peso,indicador,ativo,created_at,avaliacao) VALUES
	 ('Enfermeiro','Gestão de Qualidade','e5f92f2b-1862-4f3a-a7b3-1d27ab329045','Lidera iniciativas de segurança do paciente e promove o uso rigoroso dos EPIs.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Médico','Suporte e desenvolvimento','','O líder incentiva a desenvolvimento profissional da equipe, apoiando capacitações e o crescimento na carreira?',2,'Incentiva a equipe a fazer cursos de especialização (como suporte avançado de vida) e progredir na carreira de urgência e emergência.',true,'2026-06-30 16:29:41.288345','Liderado > Lider'),
	 ('Médico','Trabalho em Equipe','a9c9e957-4909-4e34-8b56-ccf33955ecbf','Utilizo comunicação em loop fechado (call-out e check-back) de forma consistente nos atendimentos.',1,'',true,'2026-06-11 17:47:31.017876','autoavaliacao'),
	 ('Médico','Liderança gestão','','O(s) líder coordena a equipe de forma organizada, distribuindo tarefas com clarezas e justiça?',2,'isso é fundamental para garantir que as escalas de plantão, a divisão de responsabilidades pela checagem das viaturas (insumos/medicamentos) e a limpeza da base sejam feitas de forma equilibrada, sem sobrecarregar nenhum profissional.',true,'2026-06-30 13:32:04.689644','Liderado > Lider'),
	 ('Médico','Suporte e desenvolvimento','','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',true,'2026-06-30 16:30:14.65642','Liderado > Lider'),
	 ('BP-TEAM','Habilidades Não Técnicas (NTS)','834e62a3-7ce7-4670-83b2-1b6c8d85cbf4','A equipe mantém desempenho técnico adequado mesmo em cenários de alta carga emocional',1,'',true,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Médico','Relacionamento','d804aaf2-dbdb-49a9-9c19-60b0a0c0954d','Cria um ambiente de trabalho seguro e colaborativo, onde a equipe se sente à vontade para reportar erros sem receio de represálias.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Técnico de Enfermagem','Desenvolvimento da Equipe','12188538-8020-4d91-8269-0f49372aa0cf','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Enfermeiro','Comportamental','cc839ac1-8a1e-4a07-a5ab-1c9b5e94d686','Mantém consciência situacional: monitora o estado do paciente, equipamentos e ambiente simultaneamente',1,'Consciência situacional NTS',true,'2026-06-11 15:06:08.472675','autoavaliacao'),
	 ('BP-TEAM','Liderança','8c1d69e0-bd42-46fa-aa68-69a825ce9c9c','O líder toma decisões de forma assertiva, sem hesitação excessiva, mesmo sob pressão extrema',1,'',true,'2026-06-10 10:02:38.389329','autoavaliacao');
INSERT INTO public.criterios_avaliacao (tipo,categoria,codigo,criterio,peso,indicador,ativo,created_at,avaliacao) VALUES
	 ('Médico','Liderança','09055971-3bfc-4147-aa22-ea1e9bd57a98','Utiliza comunicação em loop com a equipe, confirmando ordens e mantendo registro verbal das condutas.',2,NULL,true,'2026-06-16 14:33:45.376645','Lider > Liderado'),
	 ('Condutor','Eixo técnico','18143c0c-e75a-4cb2-b1f2-fcafba1e1ffa','Realizo autoavaliação crítica da minha prática assistências, identificando lacunas e buscando corrigi-las.',1,'Essa é uma prática fundamental e altamente recomendada na área da saúde. Realizar a autoavaliação crítica da própria prática assistencial, identificar lacunas e buscar o aprimoramento contínuo garante a segurança do paciente e a excelência no cuidado.',true,'2026-06-30 11:19:18.872887','autoavaliacao'),
	 ('Técnico de Enfermagem','Comportamental','4775db73-074f-428f-81a7-80ee54a1f888','Usa corretamente todos os EPIs e adota medidas de segurança para si, paciente e equipe em toda cena',1,'Segurança / EPIs',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Técnico de Enfermagem','Liderança','0c940522-0efa-4ae8-8e29-35d6f1df7997','Usa comunicação em loop fechado (call-out, check-back) para garantir compreensão das ordens na cena',1,'Comunicação em loop (NTS)',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Técnico de Enfermagem','Técnico-Clínico','2d7cef68-e3e6-49ba-920c-8a465b52bff3','Conhece e segue os protocolos clínicos do SAMU-192 (sepse, IAM, AVC, trauma, PCR, intoxicação)',1,'Adesão a protocolos',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Técnico de Enfermagem','Técnico-Clínico','0ecfd4d5-52da-4e27-80bd-ec289309d802','Executa técnica correta de movimentação e transporte de pacientes críticos sem agravar lesões',1,'Técnica de transporte',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
	 ('Técnico de Enfermagem','EIXO SOFT SKILLS','','Mantém foco e equilíbrio emocional em situações de alta pressão (PCR, múltiplas vítimas, violência) Controle emocional?',1,'Manter a calma em situações de alta pressão, como PCR ou múltiplas vítimas, exige treinamento e técnicas rápidas de regulação psicofisiológica.',true,'2026-06-30 13:21:21.239054','autoavaliacao'),
	 ('Condutor','Liderança gestão','','O líder demonstra domínio técnico e conhecimento das rotinas suficientes para orientar a equipe com segurança?',2,'o líder precisa dominar as rotinas operacionais (fluxos de regulação, protocolos contratuais) e os protocolos assistenciais de ponta (como o PHTLS, ACLS e diretrizes de trauma/cardio) para que a equipe sinta total segurança ao seguir suas ordens em situações críticas.',true,'2026-06-30 13:33:32.9942','Liderado > Lider'),
	 ('Técnico de Enfermagem','Gestão e Liderança','0aa5f425-638c-48dd-9e49-c94a7a6325bf','Distribui escalas, atribuições e cargas de trabalho de forma justa e equilibrada entre os membros.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Técnico de Enfermagem','EIXO SOFT SKILLS','','Mantém consciência situacional: monitora o estado do paciente, equipamentos e ambiente simultaneamente Consciência situacional NTS?',1,'A manutenção da consciência situacional (Habilidade Não Técnica - HNT) evita a fixação de foco e a sobrecarga de trabalho. Monitorar paciente, equipamentos e ambiente simultaneamente, além de identificar sinais precoces de deterioração clínica e comunicar efetivamente, previne erros e é essencial para a segurança no cuidado.',true,'2026-06-30 13:21:58.727001','autoavaliacao');
INSERT INTO public.criterios_avaliacao (tipo,categoria,codigo,criterio,peso,indicador,ativo,created_at,avaliacao) VALUES
	 ('Condutor','Comunicação e disponibilidade','','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos?',2,'A líder monitora ativamente os atendimentos diários para garantir a qualidade assistencial. Realiza o planejamento e ajuste da tripulação (escala) de forma justa e eficiente. Executa o processo de acolhimento e treinamento prático de novos colaboradores (onboarding).',true,'2026-06-30 13:34:48.761055','Liderado > Lider'),
	 ('Enfermeiro','Gestão e Liderança','4f9f4115-94ca-41e2-83aa-b7fc56f1412b','Toma decisões operacionais de forma ágil e embasada, consultando a equipe quando necessário.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Médico','Técnico / Clínico','af5e5bad-a3f5-4e0d-ba24-30a206818d2b','Comunica-se eficientemente com o médico regulador da CRUR-BF: informações precisas, decisão conjunta e tempo de regulação.',2,NULL,true,'2026-06-16 14:33:45.376645','Lider > Liderado'),
	 ('Técnico de Enfermagem','Comportamental','74c499e3-f9f8-4d57-ae1f-181573425a00','Age com ética e discrição no exercício da função.',2,NULL,true,'2026-06-16 14:33:45.376645','Lider > Liderado'),
	 ('Condutor','Comportamental','ec6b0bc2-287d-4ef2-a651-6f92dad6414d','Comunica-se de forma clara e objetiva com a equipe e com a Central de Regulação (CRUR-BF) durante o atendimento.',2,NULL,true,'2026-06-16 13:01:16.376169','Lider > Liderado'),
	 ('Condutor','Comportamental','5937a74f-38e4-4ebe-bc77-0476c378cb4e','Avalia a segurança da cena antes de se aproximar e comunica os riscos à equipe (tráfego, violência, substâncias).',2,NULL,true,'2026-06-16 13:01:16.376169','Lider > Liderado'),
	 ('Enfermeiro','Processo e Qualidade','3d79b32f-7061-4dbb-a6dd-2636967fc177','Registra o Processo de Enfermagem no SAMU de forma completa, legível e juridicamente válida',1,'Completude do Registro PE/SAMU (IVC ≥0,80)',true,'2026-06-11 15:06:08.472675','autoavaliacao'),
	 ('Enfermeiro','Comportamental','facd5e9f-2477-41aa-b0a7-67558dd6cd98','Contribui para as metas operacionais: tempo-resposta ≤ 15min, tempo de cena ≤ 20min e ROSC em PCR.',2,NULL,true,'2026-06-16 14:33:45.376645','Lider > Liderado'),
	 ('Técnico de Enfermagem','Desenvolvimento da Equipe','532ac3a5-e8a8-4b7a-90f7-bb1235f710bf','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI).',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Condutor','Metas e desenvolvimento - Transversais','d5d53635-f4d4-437d-8a71-4f68ffecede1','Busco ativamente meu desenvolvimento profissional por meio de capacitações, leituras, treinamentos inlocco, e trocas com equipe.',1,'Essa é uma excelente estratégia de carreira. Combinar capacitações, leituras e trocas com a equipe garante um desenvolvimento contínuo.',true,'2026-06-30 11:19:49.690665','autoavaliacao');
