	 ('Condutor','Comportamental','eeda4587-42bf-434a-a26b-799d2ee7f5b9','Trata pacientes, familiares e equipe com respeito, sigilo e ética, respeitando a dignidade humana',1,'Ética e humanização',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
