	 ('Condutor','Comportamental','a88af2e4-8d0f-454a-a973-d23b05252e0f','Utiliza corretamente todos os EPIs obrigatórios (luvas, máscara, avental) em todos os atendimentos',1,'Uso de EPIs',false,'2026-06-10 10:02:38.389329','autoavaliacao'),
