	 ('Médico','Técnico / Clínico','ffdfcc7a-8ec8-427a-bdb3-725ca12b2720','Aplica o protocolo de AVC (FAST/NIHSS) e aciona a linha de cuidado cerebrovascular conforme POP.',2,NULL,true,'2026-06-16 14:33:45.376645','Lider > Liderado'),
	 ('Médico','Técnico / Clínico','e6f97e73-d9b8-4d9c-abea-59efbdc88ae5','Aplica o protocolo de IAM (ACLS): ECG, trombolítico, ativação hemodinâmica, cumpre o tempo porta-balão ≤ 90min.',2,NULL,true,'2026-06-16 14:33:45.376645','Lider > Liderado'),
	 ('Técnico de Enfermagem','Técnico / Clínico','7b9a28e8-5881-4c66-8c83-ece1c87587cc','Realiza punção venosa periférica e administra medicamentos conforme prescrição do enfermeiro/médico.',2,NULL,true,'2026-06-16 13:09:10.993845','Lider > Liderado'),
	 ('Técnico de Enfermagem','Técnico / Clínico','1bd47da7-4191-4ab4-887b-b01852fa2e72','Executa corretamente compressões torácicas, ventilação (bolsa-valva-máscara) e desfibrilação com DEA.',2,NULL,true,'2026-06-16 13:09:10.993845','Lider > Liderado');
