	 ('Condutor','Processo e Qualidade','fbcb38ec-5d7b-46c4-8188-18e0bc6ef60e','Contribui para o cumprimento do tempo-resposta ≤ 15 minutos da central ao local (parâmetro SAMU/Portaria 2.048).',2,NULL,true,'2026-06-16 13:01:16.376169','Lider > Liderado'),
