	 ('Técnico de Enfermagem','Liderança Situacional','df2fb843-c55e-4514-890f-5748e10f147b','Mantém atenção à situação da ocorrência, acompanhando o estado do paciente, os equipamentos e as condições do ambiente.',2,NULL,true,'2026-06-16 14:33:45.376645','Lider > Liderado'),
	 ('Técnico de Enfermagem','Comportamental','cb105241-fc6e-4aa3-a1c1-e7a1e170bd64','Mantém controle emocional e profissionalismo em situações de alta pressão.',2,NULL,true,'2026-06-16 14:33:45.376645','Lider > Liderado'),
