INSERT INTO public.criterios_avaliacao (tipo,categoria,codigo,criterio,peso,indicador,ativo,created_at,avaliacao) VALUES
	 ('Médico','Comunicação e disponibilidade','','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos?',2,'A líder monitora ativamente os atendimentos diários para garantir a qualidade assistencial. Realiza o planejamento e ajuste da tripulação (escala) de forma justa e eficiente. Executa o processo de acolhimento e treinamento prático de novos colaboradores (onboarding).',true,'2026-06-30 13:34:48.761055','Liderado > Lider'),
	 ('Médico','Comunicação e disponibilidade','','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'1.	No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',true,'2026-06-30 13:36:05.370723','Liderado > Lider'),
	 ('Condutor','Eixo SOFT SKILLS','6e0e4bf5-37b3-40e5-bd8d-90de24cd48cd','Contribui para o cumprimento do tempo-resposta ≤15 minutos da central ao local (Portaria MS 2.048/2002)',1,'O cumprimento do tempo-resposta de ≤ 15 minutos da Central ao local exige a descentralização das bases do SAMU, dimensionamento correto da frota, otimização das rotas de tráfego e equipes capacitadas sob rigorosa regulação médica. Em locais distantes onde o tempo terrestre supere essa marca, recomenda-se o acionamento de resgate aeromédico',true,'2026-06-30 11:11:21.321903','autoavaliacao'),
	 ('Condutor','Metas e desenvolvimento - Transversais','59e49342-263c-4d4b-a0b8-5f159f7fc818','Tenho clareza sobre minhas motivações profissionais que nos mantém engajado no trabalho no SAMU 192',1,'Compreender as próprias motivações no SAMU 192 é o que fortalece a resiliência diária e o vínculo com a missão de salvar vidas.',true,'2026-06-30 11:20:41.748116','autoavaliacao'),
	 ('Condutor','Comunicação e disponibilidade','','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'1.	No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',true,'2026-06-30 13:36:05.370723','Liderado > Lider'),
	 ('Enfermeiro','Desenvolvimento da Equipe','a9d338a4-3f8c-4a89-a87b-44fc7b1c7d41','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI).',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Médico','Desenvolvimento da Equipe','c71442b1-4866-4629-85bb-dab7e2483c28','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI).',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider'),
	 ('Enfermeiro','Comunicação e disponibilidade','','O líder está disponível e acessível quando a equipe precisa de suporte, orientação ou decisão rápida?',2,'1.	onde os segundos salvam vidas e as crises operacionais acontecem a qualquer hora do dia ou da noite, ter um líder acessível para resolver impasses de frota, problemas na regulação ou conflitos na base é fundamental.',true,'2026-06-30 16:27:54.328435','Liderado > Lider'),
	 ('Técnico de Enfermagem','Suporte e desenvolvimento','','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI)?',2,'Garantir feedback mensal para 100% da equipe operacional. Identificar lacunas de competência no atendimento de urgência. ',true,'2026-06-30 16:29:11.896276','Liderado > Lider'),
	 ('Técnico de Enfermagem','Suporte e desenvolvimento','','O líder incentiva a desenvolvimento profissional da equipe, apoiando capacitações e o crescimento na carreira?',2,'Incentiva a equipe a fazer cursos de especialização (como suporte avançado de vida) e progredir na carreira de urgência e emergência.',true,'2026-06-30 16:29:41.288345','Liderado > Lider');
INSERT INTO public.criterios_avaliacao (tipo,categoria,codigo,criterio,peso,indicador,ativo,created_at,avaliacao) VALUES
	 ('Técnico de Enfermagem','Liderança gestão','','O(s) líder coordena a equipe de forma organizada, distribuindo tarefas com clarezas e justiça?',2,'isso é fundamental para garantir que as escalas de plantão, a divisão de responsabilidades pela checagem das viaturas (insumos/medicamentos) e a limpeza da base sejam feitas de forma equilibrada, sem sobrecarregar nenhum profissional.',true,'2026-06-30 13:32:04.689644','Liderado > Lider'),
	 ('Técnico de Enfermagem','Suporte e desenvolvimento','','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',true,'2026-06-30 16:30:14.65642','Liderado > Lider'),
	 ('Técnico de Enfermagem','Liderança gestão','','As decisões do líder são tomadas com transparência critérios técnicos e considerando o impacto na equipe?',2,'No contexto do SAMU, tomar decisões técnicas (como seguir à risca os protocolos de triagem ou priorização de viaturas) e explicar os motivos de forma transparente para a equipe evita boatos na base e fortalece a confiança no comando.',true,'2026-06-30 13:32:48.121518','Liderado > Lider'),
	 ('Técnico de Enfermagem','Liderança gestão','','O líder demonstra domínio técnico e conhecimento das rotinas suficientes para orientar a equipe com segurança?',2,'o líder precisa dominar as rotinas operacionais (fluxos de regulação, protocolos contratuais) e os protocolos assistenciais de ponta (como o PHTLS, ACLS e diretrizes de trauma/cardio) para que a equipe sinta total segurança ao seguir suas ordens em situações críticas.',true,'2026-06-30 13:33:32.9942','Liderado > Lider'),
	 ('Técnico de Enfermagem','Comunicação e disponibilidade','','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos?',2,'A líder monitora ativamente os atendimentos diários para garantir a qualidade assistencial. Realiza o planejamento e ajuste da tripulação (escala) de forma justa e eficiente. Executa o processo de acolhimento e treinamento prático de novos colaboradores (onboarding).',true,'2026-06-30 13:34:48.761055','Liderado > Lider'),
	 ('Técnico de Enfermagem','Comunicação e disponibilidade','','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'1.	No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',true,'2026-06-30 13:36:05.370723','Liderado > Lider'),
	 ('Enfermeiro','Suporte e desenvolvimento','','Promove e facilita atividades de educação permanente, simulações e capacitações na base do SAMU?',2,'Atuar na área de educação em urgências do SAMU, promover e facilitar atividades de educação permanente, desenvolver simulações realísticas e capacitações para a base.',true,'2026-06-30 16:28:45.057381','Liderado > Lider'),
	 ('Técnico de Enfermagem','Suporte e desenvolvimento','','Promove e facilita atividades de educação permanente, simulações e capacitações na base do SAMU?',2,'Atuar na área de educação em urgências do SAMU, promover e facilitar atividades de educação permanente, desenvolver simulações realísticas e capacitações para a base.',true,'2026-06-30 16:28:45.057381','Liderado > Lider');
